## Playwright vs Selenium：为什么选择Playwright？

Playwright是微软开源的端到端测试框架，相比Selenium有以下优势：

| 特性 | Playwright | Selenium |
|-----|-----------|----------|
| 速度 | 快（直接调用浏览器API）| 较慢（通过WebDriver） |
| API复杂度 | 简洁直观 | 较复杂 |
| 等待机制 | 自动等待，无需手动sleep | 需要显式等待 |
| 调试工具 | 内置追踪查看器 | 依赖外部工具 |
| 移动端 | 原生支持 | 需要Appium |
| 并行测试 | 内置支持 | 需配合pytest-xdist |

## 环境搭建

```bash
# 安装Playwright
npm init -y
npm install -D @playwright/test

# 安装浏览器
npx playwright install chromium
npx playwright install firefox
npx playwright install webkit
```

## 快速入门

```typescript
// tests/example.spec.ts
import { test, expect } from '@playwright/test';

test.describe('登录功能', () => {
  test.beforeEach(async ({ page }) => {
    await page.goto('https://example.com/login');
  });

  test('使用有效凭证登录成功', async ({ page }) => {
    await page.getByLabel('用户名').fill('testuser');
    await page.getByLabel('密码').fill('password123');
    await page.getByRole('button', { name: '登录' }).click();

    // 自动等待元素出现
    await expect(page.getByText('欢迎回来')).toBeVisible();
  });

  test('使用无效凭证登录失败', async ({ page }) => {
    await page.getByLabel('用户名').fill('invaliduser');
    await page.getByLabel('密码').fill('wrongpass');
    await page.getByRole('button', { name: '登录' }).click();

    await expect(page.getByRole('alert')).toContainText('用户名或密码错误');
  });
});
```

## Playwright配置

```typescript
// playwright.config.ts
import { defineConfig, devices } from '@playwright/test';

export default defineConfig({
  // 测试目录
  testDir: './tests',

  // 失败重试次数
  retries: process.env.CI ? 2 : 0,

  // 并行workers
  workers: process.env.CI ? 4 : undefined,

  // 报告器
  reporter: [
    ['html'],
    ['list'],
    ['json', { outputFile: 'test-results/results.json' }]
  ],

  // 全局超时
  timeout: 30000,

  use: {
    // 基础URL
    baseURL: 'https://example.com',

    // 截图和视频
    screenshot: 'only-on-failure',
    video: 'retain-on-failure',
    trace: 'on-first-retry',

    // 截图选项
    actionTimeout: 10000,
    navigationTimeout: 30000,
  },

  projects: [
    {
      name: 'chromium',
      use: { ...devices['Desktop Chrome'] },
    },
    {
      name: 'firefox',
      use: { ...devices['Desktop Firefox'] },
    },
    {
      name: 'webkit',
      use: { ...devices['Desktop Safari'] },
    },
    {
      name: 'Mobile Chrome',
      use: { ...devices['Pixel 5'] },
    },
  ],
});
```

## 强大的定位器API

Playwright引入了更智能的定位器概念：

```typescript
// 使用getByRole（最可靠的方式）
await page.getByRole('button', { name: '提交' }).click();
await page.getByRole('link', { name: '查看详情' }).click();

// 使用getByLabel（表单场景）
await page.getByLabel('用户名').fill('testuser');
await page.getByLabel('记住密码').check();

// 使用getByPlaceholder
await page.getByPlaceholder('输入邮箱地址').fill('test@example.com');

// 使用getByText
await page.getByText('立即注册').click();

// 使用getByTestId（需要开发配合）
await page.getByTestId('add-to-cart-btn').click();

// 组合定位器
await page
  .getByRole('listitem')
  .filter({ hasText: '产品名称' })
  .getByRole('button', { name: '删除' })
  .click();
```

## 追踪查看器（Trace Viewer）

Playwright内置的追踪查看器是强大的调试工具：

```typescript
test('追踪示例', async ({ page }) => {
  // 手动启动追踪
  const trace = await page.context().tracing.start({
    screenshots: true,
    snapshots: true,
    sources: true
  });

  await page.goto('https://example.com/cart');
  await page.getByRole('button', { name: '结算' }).click();

  // 停止追踪并保存
  await trace.stop();
  await trace.attachToTestReport();
});
```

```bash
# 本地查看追踪文件
npx playwright show-trace ./test-results/trace.zip
```

追踪查看器可以：
- 查看每一步操作的截图
- 回放用户操作
- 查看控制台日志
- 分析网络请求
- 检查DOM变化

## 网络请求拦截

```typescript
test('Mock API响应', async ({ page }) => {
  // 拦截并修改API响应
  await page.route('**/api/user/profile', route => {
    route.fulfill({
      status: 200,
      contentType: 'application/json',
      body: JSON.stringify({
        id: 1,
        name: '测试用户',
        email: 'test@example.com'
      })
    });
  });

  await page.goto('https://example.com/profile');
  await expect(page.getByText('测试用户')).toBeVisible();
});

test('监控网络请求', async ({ page }) => {
  const apiCalls: string[] = [];

  page.on('request', request => {
    if (request.url().includes('/api/')) {
      apiCalls.push(request.url());
    }
  });

  page.on('response', response => {
    if (response.url().includes('/api/')) {
      console.log(`${response.status()}: ${response.url()}`);
    }
  });

  await page.goto('https://example.com/dashboard');

  // 验证特定API被调用
  expect(apiCalls).toContain('https://example.com/api/user/info');
});
```

## 移动端测试

```typescript
test('移动端购物流程', async ({ page }) => {
  // 使用预设的移动设备
  await page.goto('https://example.com');

  // 模拟移动设备
  await page.setViewportSize({ width: 375, height: 812 });

  // 模拟触摸
  await page.touchscreen.tap(200, 300);
});

// 使用iOS Safari
test('iOS测试', async ({ browser }) => {
  const context = await browser.newContext({
    ...devices['iPhone 12'],
    locale: 'zh-CN',
    permissions: ['geolocation']
  });

  const page = await context.newPage();
  await page.goto('https://example.com');

  await context.close();
});
```

## Page Object模式

```typescript
// pages/base-page.ts
export class BasePage {
  constructor(readonly page: Page) {}

  async navigate(path: string) {
    await this.page.goto(path);
  }

  async click(selector: string) {
    await this.page.click(selector);
  }

  async fill(selector: string, value: string) {
    await this.page.fill(selector, value);
  }
}

// pages/login-page.ts
import { BasePage } from './base-page';

export class LoginPage extends BasePage {
  readonly usernameInput = () => this.page.getByLabel('用户名');
  readonly passwordInput = () => this.page.getByLabel('密码');
  readonly submitButton = () => this.page.getByRole('button', { name: '登录' });
  readonly errorAlert = () => this.page.getByRole('alert');

  async login(username: string, password: string) {
    await this.usernameInput().fill(username);
    await this.passwordInput().fill(password);
    await this.submitButton().click();
  }

  async getErrorMessage(): Promise<string> {
    return this.errorAlert().textContent() ?? '';
  }
}
```

## CI/CD集成

```yaml
# .github/workflows/playwright.yml
name: Playwright Tests

on:
  push:
    branches: [main]
  pull_request:
    branches: [main]

jobs:
  test:
    timeout-minutes: 60
    strategy:
      fail-fast: false
      matrix:
        shard: [1, 2, 3, 4]  # 分片执行

    runs-on: ubuntu-latest

    steps:
    - uses: actions/checkout@v3
    - uses: actions/setup-node@v3
      with:
        node-version: 18
        cache: 'npm'
    - name: Install dependencies
      run: npm ci
    - name: Install Playwright Browsers
      run: npx playwright install --with-deps chromium
    - name: Run Playwright tests
      run: npx playwright test --shard=${{ matrix.shard }}/${{ strategy.job.total }}
```

## 最佳实践

1. 使用定位器而非原始选择器
2. 利用自动等待
3. 测试隔离：每个测试前创建新context
4. 合理的超时设置

Playwright为企业级端到端测试提供了完整的解决方案，值得深入学习和应用。
